import React, {useEffect, useState} from "react";
import axios from "axios";
import "./App.css";

function App(){
 const [leads,setLeads]=useState([]);

 useEffect(()=>{
   axios.get("http://localhost:5000/leads")
   .then(res=>setLeads(res.data));
 },[]);

 return (
  <div className="app">
   <header className="header">
    <h1>CRM Lead Management</h1>
    <p>Manage client leads generated from website forms</p>
   </header>

   <div className="container">
    <div className="stats">
     <div className="card"><h3>Total Leads</h3><b>{leads.length}</b></div>
     <div className="card"><h3>New Leads</h3><b>{leads.filter(x=>x.status==="new").length}</b></div>
     <div className="card"><h3>Converted</h3><b>{leads.filter(x=>x.status==="converted").length}</b></div>
    </div>

    <div className="panel">
     <h2>Lead List</h2>
     <div className="tableBox">
      <table>
       <thead><tr><th>Name</th><th>Email</th><th>Source</th><th>Status</th><th>Notes</th></tr></thead>
       <tbody>
       {leads.map(l=>
        <tr key={l.id}>
         <td>{l.name}</td><td>{l.email}</td><td>{l.source}</td>
         <td><span className={"status "+l.status}>{l.status}</span></td>
         <td>{l.notes}</td>
        </tr>)}
       </tbody>
      </table>
     </div>
    </div>
   </div>
  </div>
 );
}
export default App;
